"use client";

import { motion } from "framer-motion";
import { LESSON_STEPS, PHASE_COLORS, type LessonStepId } from "@/lib/lesson-data";

type Props = {
  currentStep: number;
  onPrev: () => void;
  onNext: () => void;
  onJump: (step: number) => void;
  accent: string;
};

export function StepNavigator({ currentStep, onPrev, onNext, onJump, accent }: Props) {
  const step = LESSON_STEPS[currentStep];
  const isFirst = currentStep === 0;
  const isLast = currentStep === LESSON_STEPS.length - 1;

  return (
    <div className="border-t-3 border-black bg-white">
      {/* Progress dots */}
      <div className="flex items-center gap-1 overflow-x-auto px-4 py-3">
        {LESSON_STEPS.map((s, i) => (
          <button
            key={s.id}
            onClick={() => onJump(i)}
            title={s.title}
            className="group relative flex shrink-0 flex-col items-center gap-1"
          >
            <motion.div
              animate={{
                backgroundColor:
                  i === currentStep
                    ? accent
                    : i < currentStep
                      ? PHASE_COLORS[s.phase]
                      : "#E8E8E8",
                scale: i === currentStep ? 1.3 : 1,
              }}
              className="h-2.5 w-2.5 border border-black"
            />
            {i === currentStep && (
              <span className="absolute -top-6 whitespace-nowrap font-mono text-[8px] font-bold uppercase tracking-wider text-black/50">
                {s.phase}
              </span>
            )}
          </button>
        ))}
      </div>

      <div className="flex items-center justify-between gap-4 border-t-3 border-black px-5 py-4">
        <button
          onClick={onPrev}
          disabled={isFirst}
          className="border-3 border-black px-5 py-2 font-mono text-xs font-bold uppercase disabled:opacity-30"
          style={{ boxShadow: isFirst ? "none" : "3px 3px 0 #0A0A0A" }}
        >
          ← Back
        </button>

        <div className="text-center">
          <p className="font-mono text-[9px] font-bold uppercase tracking-widest text-black/40">
            Step {currentStep + 1} / {LESSON_STEPS.length}
          </p>
          <p className="text-sm font-black uppercase">{step.title}</p>
        </div>

        <button
          onClick={onNext}
          disabled={isLast}
          className="border-3 border-black px-5 py-2 font-mono text-xs font-bold uppercase text-white disabled:opacity-30"
          style={{
            backgroundColor: isLast ? "#888" : accent,
            boxShadow: isLast ? "none" : `3px 3px 0 #0A0A0A`,
          }}
        >
          Next →
        </button>
      </div>
    </div>
  );
}
