"use client";

import { motion } from "framer-motion";
import type { TeachingDataset } from "@/lib/lesson-data";

type Props = {
  data: TeachingDataset;
  highlightRows?: number[];
  highlightCols?: number[];
  highlightCells?: { row: number; col: number }[];
  dimOutside?: boolean;
  scrambledRowOrder?: number[];
  scrambledColOrder?: number[];
  accent?: string;
  animateCells?: boolean;
};

function ratingColor(v: number, accent: string): string {
  if (v >= 4) return accent;
  if (v >= 3) return "#FFD23F";
  return "#E8E8E8";
}

export function RawDataTable({
  data,
  highlightRows = [],
  highlightCols = [],
  highlightCells = [],
  dimOutside = false,
  scrambledRowOrder,
  scrambledColOrder,
  accent,
  animateCells = true,
}: Props) {
  const color = accent ?? data.theme.accent;
  const rowOrder = scrambledRowOrder ?? data.rows.map((_, i) => i);
  const colOrder = scrambledColOrder ?? data.cols.map((_, i) => i);

  const isCellHighlighted = (r: number, c: number) => {
    if (highlightCells.some((h) => h.row === r && h.col === c)) return true;
    if (highlightRows.includes(r) && highlightCols.includes(c)) return true;
    if (highlightRows.length && highlightCols.length) {
      return highlightRows.includes(r) && highlightCols.includes(c);
    }
    return highlightRows.includes(r) || highlightCols.includes(c);
  };

  const isDimmed = (r: number, c: number) => {
    if (!dimOutside) return false;
    const hasHighlight =
      highlightRows.length > 0 || highlightCols.length > 0 || highlightCells.length > 0;
    if (!hasHighlight) return false;
    return !isCellHighlighted(r, c);
  };

  return (
    <div className="inline-block overflow-x-auto">
      <table className="border-collapse font-mono text-sm">
        <thead>
          <tr>
            <th className="border-3 border-black bg-black px-3 py-2 text-left text-[10px] font-bold uppercase tracking-widest text-white">
              {data.rowLabel} ↓
            </th>
            {colOrder.map((ci) => (
              <th
                key={data.cols[ci]}
                className="border-3 border-black px-3 py-2 text-center text-[10px] font-bold uppercase"
                style={{
                  backgroundColor: highlightCols.includes(ci) ? color : "#F0F0F0",
                  color: highlightCols.includes(ci) ? "#FFF" : "#0A0A0A",
                }}
              >
                {data.cols[ci]}
              </th>
            ))}
          </tr>
        </thead>
        <tbody>
          {rowOrder.map((ri, displayRow) => (
            <tr key={data.rows[ri]}>
              <td
                className="border-3 border-black px-3 py-2 font-bold"
                style={{
                  backgroundColor: highlightRows.includes(ri) ? color : "#F0F0F0",
                  color: highlightRows.includes(ri) ? "#FFF" : "#0A0A0A",
                }}
              >
                {data.rows[ri]}
              </td>
              {colOrder.map((ci, displayCol) => {
                const val = data.matrix[ri][ci];
                const dimmed = isDimmed(ri, ci);
                const highlighted = isCellHighlighted(ri, ci);
                return (
                  <motion.td
                    key={`${ri}-${ci}`}
                    layout={animateCells}
                    initial={animateCells ? { opacity: 0, scale: 0.8 } : false}
                    animate={{
                      opacity: dimmed ? 0.2 : 1,
                      scale: 1,
                      backgroundColor: highlighted
                        ? `${color}33`
                        : ratingColor(val, color),
                    }}
                    transition={{ delay: displayRow * 0.05 + displayCol * 0.03, type: "spring" }}
                    className="border-3 border-black px-4 py-3 text-center text-lg font-black"
                    style={{
                      outline: highlighted ? `3px solid ${color}` : undefined,
                      outlineOffset: -3,
                    }}
                  >
                    {val}
                  </motion.td>
                );
              })}
            </tr>
          ))}
        </tbody>
      </table>
      <p className="mt-2 font-mono text-[9px] uppercase tracking-widest text-black/40">
        {data.valueLabel}
      </p>
    </div>
  );
}
