"use client";

import { useState } from "react";
import { AnimatePresence, motion } from "framer-motion";
import {
  LESSON_STEPS,
  PHASE_COLORS,
  TEACHING_DATASETS,
  getTeachingDataset,
  type LessonStepId,
} from "@/lib/lesson-data";
import { starsLabel } from "@/lib/heatmap-utils";
import { RawDataTable } from "./RawDataTable";
import { VectorDisplay } from "./VectorDisplay";
import { DistanceCalculator } from "./DistanceCalculator";
import { DistanceMatrixView } from "./DistanceMatrixView";
import { ClusterReveal } from "./ClusterReveal";
import { StepNavigator } from "./StepNavigator";

const SCRAMBLED_ROWS = [2, 0, 3, 1];
const SCRAMBLED_COLS = [2, 3, 0, 1];

type Props = {
  datasetId: string;
  onDatasetChange: (id: string) => void;
};

export function LessonWizard({ datasetId, onDatasetChange }: Props) {
  const data = getTeachingDataset(datasetId);
  const [stepIndex, setStepIndex] = useState(0);
  const [rowA, setRowA] = useState(data.similarRowPair[0]);
  const [rowB, setRowB] = useState(data.similarRowPair[1]);
  const [colA, setColA] = useState(data.similarColPair[0]);
  const [colB, setColB] = useState(2);

  const step = LESSON_STEPS[stepIndex];
  const accent = data.theme.accent;

  const goNext = () => setStepIndex((s) => Math.min(s + 1, LESSON_STEPS.length - 1));
  const goPrev = () => setStepIndex((s) => Math.max(s - 1, 0));
  const goJump = (i: number) => setStepIndex(i);

  const handleDatasetChange = (id: string) => {
    onDatasetChange(id);
    setStepIndex(0);
    const d = getTeachingDataset(id);
    setRowA(d.similarRowPair[0]);
    setRowB(d.similarRowPair[1]);
    setColA(d.similarColPair[0]);
    setColB(2);
  };

  return (
    <div className="border-3 border-black bg-white" style={{ boxShadow: `8px 8px 0 ${accent}` }}>
      {/* Header */}
      <div
        className="flex flex-wrap items-center justify-between gap-3 border-b-3 border-black px-5 py-4"
        style={{ backgroundColor: data.theme.accentLight }}
      >
        <div>
          <p className="font-mono text-[9px] font-bold uppercase tracking-[0.2em] text-black/50">
            Guided lesson · step by step
          </p>
          <h2 className="text-xl font-black uppercase">{data.title}</h2>
        </div>
        <div className="flex flex-wrap gap-1">
          {TEACHING_DATASETS.map((d) => (
            <button
              key={d.id}
              onClick={() => handleDatasetChange(d.id)}
              className="border-2 border-black px-2 py-1 font-mono text-[9px] font-bold uppercase"
              style={{
                backgroundColor: datasetId === d.id ? d.theme.accent : "#FFF",
                color: datasetId === d.id ? "#FFF" : "#0A0A0A",
              }}
            >
              {d.id}
            </button>
          ))}
        </div>
      </div>

      {/* Phase banner */}
      <div
        className="flex items-center gap-3 border-b-3 border-black px-5 py-2"
        style={{ backgroundColor: PHASE_COLORS[step.phase] + "22" }}
      >
        <span
          className="border-2 border-black px-2 py-0.5 font-mono text-[9px] font-bold uppercase text-white"
          style={{ backgroundColor: PHASE_COLORS[step.phase] }}
        >
          {step.phase}
        </span>
        <div>
          <p className="text-sm font-black uppercase">{step.title}</p>
          <p className="text-xs text-black/60">{step.subtitle}</p>
        </div>
      </div>

      {/* Step content */}
      <div className="min-h-[420px] px-5 py-6">
        <AnimatePresence mode="wait">
          <motion.div
            key={`${datasetId}-${step.id}`}
            initial={{ opacity: 0, x: 24 }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: -24 }}
            transition={{ duration: 0.25 }}
          >
            <StepContent
              stepId={step.id}
              data={data}
              accent={accent}
              rowA={rowA}
              rowB={rowB}
              colA={colA}
              colB={colB}
              onRowA={setRowA}
              onRowB={setRowB}
              onColA={setColA}
              onColB={setColB}
              onJumpToStep={(id) => {
                const idx = LESSON_STEPS.findIndex((s) => s.id === id);
                if (idx >= 0) setStepIndex(idx);
              }}
            />
          </motion.div>
        </AnimatePresence>
      </div>

      <StepNavigator
        currentStep={stepIndex}
        onPrev={goPrev}
        onNext={goNext}
        onJump={goJump}
        accent={accent}
      />
    </div>
  );
}

function StepContent({
  stepId,
  data,
  accent,
  rowA,
  rowB,
  colA,
  colB,
  onRowA,
  onRowB,
  onColA,
  onColB,
  onJumpToStep,
}: {
  stepId: LessonStepId;
  data: ReturnType<typeof getTeachingDataset>;
  accent: string;
  rowA: number;
  rowB: number;
  colA: number;
  colB: number;
  onRowA: (i: number) => void;
  onRowB: (i: number) => void;
  onColA: (i: number) => void;
  onColB: (i: number) => void;
  onJumpToStep: (id: LessonStepId) => void;
}) {
  switch (stepId) {
    case "intro":
      return (
        <div className="space-y-5">
          <Callout accent={accent}>
            You have a <strong>matrix</strong>: {data.rows.length} {data.rowLabel} (rows) ×{" "}
            {data.cols.length} {data.colLabel} (columns). Each cell is a number —{" "}
            {data.valueLabel}.
          </Callout>
          <div className="grid gap-4 sm:grid-cols-2">
            <InfoBox title="Rows" body={`Each row is one ${data.rowUnit}. Row clustering asks: which ${data.rowLabel.toLowerCase()} behave similarly?`} color={accent} />
            <InfoBox title="Columns" body={`Each column is one ${data.colUnit}. Column clustering asks: which ${data.colLabel.toLowerCase()} receive similar values?`} color="#0066FF" />
          </div>
          <p className="text-xs text-black/50">
            {starsLabel(data.stars)} · We&apos;ll use a small {data.rows.length}×{data.cols.length} example so every number is easy to follow.
          </p>
        </div>
      );

    case "raw-table":
      return (
        <div className="space-y-4">
          <Callout accent={accent}>
            This is your raw data table. Read it like a spreadsheet:{" "}
            <strong>{data.rows[0]}</strong> gave <strong>{data.cols[0]}</strong> a rating of{" "}
            <strong>{data.matrix[0][0]}</strong>.
          </Callout>
          <div className="flex justify-center">
            <RawDataTable data={data} accent={accent} />
          </div>
          <p className="text-center text-xs text-black/50">
            5 = loves / frequent &nbsp;·&nbsp; 1 = dislikes / rare
          </p>
        </div>
      );

    case "row-vectors":
      return (
        <div className="space-y-4">
          <Callout accent={accent}>
            <strong>Row clustering:</strong> treat each row as a <em>vector</em> — a list of numbers.
            Compare vectors to find similar rows.
          </Callout>
          <VectorDisplay data={data} mode="row" accent={accent} />
        </div>
      );

    case "row-compare-similar":
      return (
        <div className="space-y-4">
          <Callout accent={accent}>
            Which {data.rowLabel.toLowerCase()} have similar patterns? Let&apos;s compare{" "}
            <strong>{data.rows[data.similarRowPair[0]]}</strong> and{" "}
            <strong>{data.rows[data.similarRowPair[1]]}</strong> using Euclidean distance.
          </Callout>
          <DistanceCalculator
            data={data}
            mode="row"
            indexA={rowA}
            indexB={rowB}
            accent={accent}
            interactive
            onChangeA={onRowA}
            onChangeB={onRowB}
          />
        </div>
      );

    case "row-compare-different":
      return (
        <div className="space-y-4">
          <Callout accent="#FF0040">
            Now compare <strong>{data.rows[data.differentRowPair[0]]}</strong> vs{" "}
            <strong>{data.rows[data.differentRowPair[1]]}</strong> — totally different tastes.
          </Callout>
          <DistanceCalculator
            data={data}
            mode="row"
            indexA={data.differentRowPair[0]}
            indexB={data.differentRowPair[1]}
            accent={accent}
          />
        </div>
      );

    case "row-distance-matrix":
      return (
        <div className="space-y-4">
          <Callout accent={accent}>
            Compare <em>every</em> row to <em>every</em> other row. Click a cell to inspect that pair.
          </Callout>
          <DistanceMatrixView
            data={data}
            mode="row"
            accent={accent}
            highlightPair={[rowA, rowB]}
            onCellClick={(i, j) => {
              onRowA(i);
              onRowB(j);
              onJumpToStep("row-compare-similar");
            }}
          />
        </div>
      );

    case "row-clusters":
      return (
        <div className="space-y-4">
          <ClusterReveal data={data} mode="row" accent={accent} />
        </div>
      );

    case "row-reorder":
      return (
        <div className="space-y-4">
          <Callout accent={accent}>
            <strong>Row clustering result:</strong> similar rows are placed next to each other.
            Columns stay in their original order — only rows move.
          </Callout>
          <div className="grid gap-6 lg:grid-cols-2">
            <div>
              <p className="mb-2 font-mono text-[9px] font-bold uppercase text-black/40">Before (scrambled)</p>
              <RawDataTable data={data} scrambledRowOrder={SCRAMBLED_ROWS} accent={accent} animateCells={false} />
            </div>
            <div>
              <p className="mb-2 font-mono text-[9px] font-bold uppercase" style={{ color: accent }}>
                After row clustering ↓
              </p>
              <RawDataTable
                data={data}
                highlightRows={data.rowClusters.flatMap((c) => c.indices)}
                accent={accent}
              />
            </div>
          </div>
          <KeyIntuition text={`"${data.rowClusterInsight}" — horizontal bands of similar values appear.`} />
        </div>
      );

    case "col-vectors":
      return (
        <div className="space-y-4">
          <Callout accent="#0066FF">
            <strong>Flip your thinking.</strong> Instead of comparing users, compare{" "}
            {data.colLabel.toLowerCase()}. Each <em>column</em> is now a vector.
          </Callout>
          <VectorDisplay data={data} mode="col" accent="#0066FF" />
        </div>
      );

    case "col-compare":
      return (
        <div className="space-y-4">
          <Callout accent="#0066FF">
            <strong>{data.cols[data.similarColPair[0]]}</strong> and{" "}
            <strong>{data.cols[data.similarColPair[1]]}</strong> have very similar column vectors.
          </Callout>
          <DistanceCalculator
            data={data}
            mode="col"
            indexA={colA}
            indexB={data.similarColPair[1]}
            accent="#0066FF"
            interactive
            onChangeA={onColA}
            onChangeB={onColB}
          />
        </div>
      );

    case "col-clusters":
      return <ClusterReveal data={data} mode="col" accent="#0066FF" />;

    case "col-reorder":
      return (
        <div className="space-y-4">
          <Callout accent="#0066FF">
            <strong>Column clustering result:</strong> similar columns grouped together. Rows stay fixed.
          </Callout>
          <div className="grid gap-6 lg:grid-cols-2">
            <div>
              <p className="mb-2 font-mono text-[9px] font-bold uppercase text-black/40">Before (scrambled)</p>
              <RawDataTable data={data} scrambledColOrder={SCRAMBLED_COLS} accent="#0066FF" animateCells={false} />
            </div>
            <div>
              <p className="mb-2 font-mono text-[9px] font-bold uppercase text-[#0066FF]">After column clustering →</p>
              <RawDataTable
                data={data}
                highlightCols={data.colClusters.flatMap((c) => c.indices)}
                accent="#0066FF"
              />
            </div>
          </div>
          <KeyIntuition text={`"${data.colClusterInsight}" — vertical bands of similar values appear.`} />
        </div>
      );

    case "bicluster-intro":
      return (
        <div className="space-y-5">
          <Callout accent="#FFE600">
            Normal clustering does <strong>rows only</strong> OR <strong>columns only</strong> — never both.
            Biclustering does <strong>both simultaneously</strong>.
          </Callout>
          <div className="grid gap-3 sm:grid-cols-3">
            <LimitCard title="Row only" desc="Groups similar rows. Columns unchanged." active={false} />
            <LimitCard title="Column only" desc="Groups similar columns. Rows unchanged." active={false} />
            <LimitCard title="Bicluster" desc="Finds a row group AND column group together." active highlight="#FFE600" />
          </div>
          <p className="text-sm text-black/70">{data.biclusterInsight}</p>
        </div>
      );

    case "bicluster-reveal":
      return (
        <div className="space-y-4">
          <Callout accent="#FFE600">
            The bicluster:{" "}
            <strong>
              {data.bicluster.rowIndices.map((i) => data.rows[i]).join(", ")}
            </strong>{" "}
            ×{" "}
            <strong>
              {data.bicluster.colIndices.map((i) => data.cols[i]).join(", ")}
            </strong>
            . Everything outside this block is irrelevant to this pattern.
          </Callout>
          <div className="flex justify-center">
            <RawDataTable
              data={data}
              highlightRows={data.bicluster.rowIndices}
              highlightCols={data.bicluster.colIndices}
              dimOutside
              accent="#FFE600"
            />
          </div>
          <motion.div
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            className="border-3 border-black p-4"
            style={{ backgroundColor: "#FFE60022", boxShadow: "5px 5px 0 #FFE600" }}
          >
            <p className="font-mono text-[10px] font-bold uppercase">{data.bicluster.label}</p>
            <p className="mt-2 text-sm font-medium">{data.bicluster.meaning}</p>
          </motion.div>
        </div>
      );

    case "summary":
      return (
        <div className="space-y-4">
          <div className="grid gap-3 sm:grid-cols-3">
            <SummaryCard
              title="Row clustering"
              color={accent}
              question={data.rowClusterInsight}
              result={data.rowClusters.map((c) => c.meaning).join(" · ")}
            />
            <SummaryCard
              title="Column clustering"
              color="#0066FF"
              question={data.colClusterInsight}
              result={data.colClusters.map((c) => c.meaning).join(" · ")}
            />
            <SummaryCard
              title="Biclustering"
              color="#FFE600"
              question="Both axes at once"
              result={data.bicluster.meaning}
            />
          </div>
          <div className="border-3 border-black bg-black p-5 text-white">
            <p className="font-mono text-[10px] font-bold uppercase tracking-widest text-white/50">
              Formula
            </p>
            <p className="mt-2 font-mono text-lg">d(x,y) = √(Σ(xᵢ − yᵢ)²)</p>
            <p className="mt-2 text-sm text-white/70">Euclidean Distance — the most common metric for clustering.</p>
          </div>
        </div>
      );

    default:
      return null;
  }
}

function Callout({ children, accent }: { children: React.ReactNode; accent: string }) {
  return (
    <div
      className="border-l-4 bg-white p-4 text-sm leading-relaxed"
      style={{ borderColor: accent, backgroundColor: `${accent}08` }}
    >
      {children}
    </div>
  );
}

function InfoBox({ title, body, color }: { title: string; body: string; color: string }) {
  return (
    <div className="border-3 border-black p-4" style={{ boxShadow: `4px 4px 0 ${color}` }}>
      <p className="font-mono text-[10px] font-bold uppercase" style={{ color }}>
        {title}
      </p>
      <p className="mt-2 text-xs leading-relaxed text-black/70">{body}</p>
    </div>
  );
}

function KeyIntuition({ text }: { text: string }) {
  return (
    <div className="border-3 border-black bg-black px-4 py-3 text-sm font-medium text-white">
      Key intuition: {text}
    </div>
  );
}

function LimitCard({
  title,
  desc,
  active,
  highlight,
}: {
  title: string;
  desc: string;
  active?: boolean;
  highlight?: string;
}) {
  return (
    <div
      className="border-3 border-black p-3"
      style={{
        backgroundColor: active ? `${highlight}22` : "#FFF",
        boxShadow: active ? `4px 4px 0 ${highlight}` : "2px 2px 0 #0A0A0A",
      }}
    >
      <p className="text-xs font-black uppercase">{title}</p>
      <p className="mt-1 text-[11px] text-black/60">{desc}</p>
    </div>
  );
}

function SummaryCard({
  title,
  color,
  question,
  result,
}: {
  title: string;
  color: string;
  question: string;
  result: string;
}) {
  return (
    <div className="border-3 border-black p-4" style={{ boxShadow: `4px 4px 0 ${color}` }}>
      <p className="font-mono text-[9px] font-bold uppercase" style={{ color }}>
        {title}
      </p>
      <p className="mt-2 text-xs font-bold">{question}</p>
      <p className="mt-2 text-[11px] leading-relaxed text-black/60">{result}</p>
    </div>
  );
}
