"use client";

import { motion } from "framer-motion";
import type { TeachingDataset } from "@/lib/lesson-data";
import { buildDistanceMatrix } from "@/lib/math";

type Props = {
  data: TeachingDataset;
  mode: "row" | "col";
  accent: string;
  onCellClick?: (i: number, j: number) => void;
  highlightPair?: [number, number];
};

export function DistanceMatrixView({
  data,
  mode,
  accent,
  onCellClick,
  highlightPair,
}: Props) {
  const labels = mode === "row" ? data.rows : data.cols;
  const vectors =
    mode === "row"
      ? data.matrix
      : data.cols.map((_, j) => data.matrix.map((row) => row[j]));

  const dist = buildDistanceMatrix(vectors);
  const maxD = Math.max(...dist.flat());

  return (
    <div>
      <p className="mb-3 text-xs text-black/60">
        Darker = closer (more similar). Click any cell to inspect that pair.
      </p>
      <div className="inline-block">
        <table className="border-collapse font-mono text-xs">
          <thead>
            <tr>
              <th className="border-2 border-black bg-black p-2 text-white" />
              {labels.map((l) => (
                <th key={l} className="border-2 border-black bg-black p-2 text-[9px] font-bold text-white">
                  {l}
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {dist.map((row, i) => (
              <tr key={labels[i]}>
                <td className="border-2 border-black bg-black p-2 text-[9px] font-bold text-white">
                  {labels[i]}
                </td>
                {row.map((d, j) => {
                  const isHighlight =
                    highlightPair &&
                    ((highlightPair[0] === i && highlightPair[1] === j) ||
                      (highlightPair[0] === j && highlightPair[1] === i));
                  const t = i === j ? 0 : 1 - d / maxD;
                  const bg =
                    i === j
                      ? "#E8E8E8"
                      : `rgba(${parseInt(accent.slice(1, 3), 16)}, ${parseInt(accent.slice(3, 5), 16)}, ${parseInt(accent.slice(5, 7), 16)}, ${0.15 + t * 0.85})`;

                  return (
                    <motion.td
                      key={j}
                      whileHover={{ scale: 1.1 }}
                      onClick={() => i !== j && onCellClick?.(i, j)}
                      className="cursor-pointer border-2 border-black p-2 text-center font-bold"
                      style={{
                        backgroundColor: bg,
                        color: t > 0.6 ? "#FFF" : "#0A0A0A",
                        outline: isHighlight ? `3px solid ${accent}` : undefined,
                        outlineOffset: -3,
                      }}
                    >
                      {i === j ? "—" : d.toFixed(1)}
                    </motion.td>
                  );
                })}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}
