"use client";

import { useMemo } from "react";
import { motion } from "framer-motion";
import type { TeachingDataset } from "@/lib/lesson-data";
import { distanceLabel, euclideanBreakdown } from "@/lib/math";

type Props = {
  data: TeachingDataset;
  mode: "row" | "col";
  indexA: number;
  indexB: number;
  accent: string;
  interactive?: boolean;
  onChangeA?: (i: number) => void;
  onChangeB?: (i: number) => void;
};

export function DistanceCalculator({
  data,
  mode,
  indexA,
  indexB,
  accent,
  interactive = false,
  onChangeA,
  onChangeB,
}: Props) {
  const labels = mode === "row" ? data.rows : data.cols;
  const dimLabels = mode === "row" ? data.cols : data.rows;

  const vecA = useMemo(
    () =>
      mode === "row"
        ? data.matrix[indexA]
        : data.matrix.map((row) => row[indexA]),
    [data, mode, indexA],
  );
  const vecB = useMemo(
    () =>
      mode === "row"
        ? data.matrix[indexB]
        : data.matrix.map((row) => row[indexB]),
    [data, mode, indexB],
  );

  const { distance, terms } = euclideanBreakdown(vecA, vecB, dimLabels);
  const label = distanceLabel(distance);
  const isClose = distance < 3;

  const picker = (value: number, onChange?: (i: number) => void) => (
    <div className="flex flex-wrap gap-1">
      {labels.map((l, i) => (
        <button
          key={l}
          onClick={() => onChange?.(i)}
          className="border-2 border-black px-2 py-1 font-mono text-[10px] font-bold uppercase transition-colors"
          style={{
            backgroundColor: value === i ? accent : "#F5F5F5",
            color: value === i ? "#FFF" : "#0A0A0A",
          }}
        >
          {l}
        </button>
      ))}
    </div>
  );

  return (
    <div className="space-y-5">
      {interactive && (
        <div className="grid gap-4 sm:grid-cols-2">
          <div>
            <p className="mb-2 font-mono text-[9px] font-bold uppercase tracking-widest text-black/50">
              Pick A
            </p>
            {picker(indexA, onChangeA)}
          </div>
          <div>
            <p className="mb-2 font-mono text-[9px] font-bold uppercase tracking-widest text-black/50">
              Pick B
            </p>
            {picker(indexB, onChangeB)}
          </div>
        </div>
      )}

      <div className="grid gap-3 sm:grid-cols-2">
        <VectorChip label={labels[indexA]} vector={vecA} accent={accent} />
        <VectorChip label={labels[indexB]} vector={vecB} accent="#888" />
      </div>

      <motion.div
        key={`${indexA}-${indexB}-${distance}`}
        initial={{ opacity: 0, y: 8 }}
        animate={{ opacity: 1, y: 0 }}
        className="border-3 border-black bg-white p-5"
        style={{ boxShadow: `6px 6px 0 ${isClose ? accent : "#0A0A0A"}` }}
      >
        <p className="font-mono text-[10px] font-bold uppercase tracking-widest text-black/50">
          Euclidean distance formula
        </p>
        <p className="mt-3 font-mono text-sm leading-relaxed">
          d(<span style={{ color: accent }}>{labels[indexA]}</span>,{" "}
          <span style={{ color: accent }}>{labels[indexB]}</span>) = √(
          {terms.map((t, i) => (
            <span key={t.index}>
              {i > 0 && " + "}
              <motion.span
                initial={{ backgroundColor: "#FFE600" }}
                animate={{ backgroundColor: "transparent" }}
                transition={{ duration: 1.2 }}
                className="px-0.5"
              >
                ({t.a}−{t.b})²
              </motion.span>
            </span>
          ))}
          )
        </p>

        <div className="mt-4 space-y-1">
          {terms.map((t, i) => (
            <motion.p
              key={t.index}
              initial={{ opacity: 0, x: -10 }}
              animate={{ opacity: 1, x: 0 }}
              transition={{ delay: i * 0.08 }}
              className="font-mono text-xs text-black/70"
            >
              ({t.a}−{t.b})² = ({t.diff})² = {t.squared}
              <span className="ml-2 text-black/40">← {t.label}</span>
            </motion.p>
          ))}
        </div>

        <div
          className="mt-5 flex flex-wrap items-center gap-3 border-t-3 border-black pt-4"
        >
          <span className="font-mono text-2xl font-black" style={{ color: accent }}>
            d = √{terms.reduce((s, t) => s + t.squared, 0)} = {distance.toFixed(2)}
          </span>
          <span
            className="border-2 border-black px-3 py-1 font-mono text-xs font-bold uppercase"
            style={{
              backgroundColor: isClose ? accent : "#FF0040",
              color: "#FFF",
            }}
          >
            {label}
          </span>
        </div>

        <p className="mt-3 text-sm font-medium text-black/70">
          {isClose
            ? `→ ${labels[indexA]} and ${labels[indexB]} have similar patterns. They'd end up in the same cluster.`
            : `→ ${labels[indexA]} and ${labels[indexB]} are very different. They'd be in separate clusters.`}
        </p>
      </motion.div>
    </div>
  );
}

function VectorChip({
  label,
  vector,
  accent,
}: {
  label: string;
  vector: number[];
  accent: string;
}) {
  return (
    <div className="border-2 border-black p-3" style={{ backgroundColor: `${accent}10` }}>
      <p className="font-mono text-[10px] font-bold uppercase text-black/50">{label}</p>
      <p className="mt-1 font-mono text-sm font-bold">[{vector.join(", ")}]</p>
    </div>
  );
}
