"use client";

import { motion } from "framer-motion";
import type { TeachingDataset } from "@/lib/lesson-data";

const CLUSTER_COLORS = ["#FF2D6B", "#0066FF", "#FFE600", "#00E5A0"];

type Props = {
  data: TeachingDataset;
  mode: "row" | "col";
  accent: string;
};

export function ClusterReveal({ data, mode, accent }: Props) {
  const clusters = mode === "row" ? data.rowClusters : data.colClusters;
  const unit = mode === "row" ? data.rowUnit : data.colUnit;
  const items = mode === "row" ? data.rows : data.cols;

  return (
    <div className="space-y-4">
      <p className="text-sm font-medium text-black/70">
        {mode === "row" ? data.rowClusterInsight : data.colClusterInsight}
      </p>
      <div className="grid gap-4 sm:grid-cols-2">
        {clusters.map((cluster, ci) => {
          const color = CLUSTER_COLORS[ci % CLUSTER_COLORS.length];
          return (
            <motion.div
              key={cluster.name}
              initial={{ opacity: 0, y: 16 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: ci * 0.15 }}
              className="border-3 border-black p-4"
              style={{ backgroundColor: `${color}12`, boxShadow: `5px 5px 0 ${color}` }}
            >
              <div className="flex items-center gap-2">
                <span
                  className="border-2 border-black px-2 py-0.5 font-mono text-[10px] font-bold uppercase text-white"
                  style={{ backgroundColor: color }}
                >
                  {cluster.name}
                </span>
              </div>
              <div className="mt-3 flex flex-wrap gap-2">
                {cluster.indices.map((idx, i) => (
                  <motion.span
                    key={items[idx]}
                    initial={{ scale: 0 }}
                    animate={{ scale: 1 }}
                    transition={{ delay: ci * 0.15 + i * 0.1 }}
                    className="border-2 border-black px-3 py-1 font-mono text-sm font-bold"
                    style={{ backgroundColor: color, color: "#FFF" }}
                  >
                    {items[idx]}
                  </motion.span>
                ))}
              </div>
              <p className="mt-3 text-xs font-semibold leading-relaxed" style={{ color }}>
                {cluster.meaning}
              </p>
            </motion.div>
          );
        })}
      </div>

      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ delay: 0.5 }}
        className="border-3 border-black bg-black p-4 text-white"
      >
        <p className="font-mono text-[10px] font-bold uppercase tracking-widest text-white/50">
          Formula used
        </p>
        <p className="mt-2 font-mono text-sm">
          d(x, y) = √Σ(xᵢ − yᵢ)² &nbsp;·&nbsp; Euclidean Distance
        </p>
        <p className="mt-2 text-xs text-white/70">
          Small distance → same cluster. Large distance → different cluster.
        </p>
      </motion.div>
    </div>
  );
}
